def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 5):
                penalty += (ratio ** (4 * k)) / (k ** 2 + 1)
            priorities[i] = ratio ** 4 + penalty + np.log1p(ratio)
        elif 1 < ratio <= 2:
            weights = [3, -2, 1, -0.5]
            weighted_sum = 0
            for idx, w in enumerate(weights, 1):
                weighted_sum += w * (ratio ** (2 * idx))
            base = abs(weighted_sum) * 20
            extra = 0
            for m in range(1, 6):
                term = ((-1) ** m) * (ratio ** m) / (m + 2)
                extra += term
            priorities[i] = base + extra + np.sin(ratio * np.pi)
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j ** 0.5)
                score += term
            if ratio < 0.25:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 15
            elif ratio < 0.75:
                multiplier = 7
            else:
                multiplier = 3
            priorities[i] = abs(score) * multiplier
            if 0.7 < ratio < 1:
                extra = 0
                for m in range(1, 5):
                    extra += (ratio ** m) / (m + 0.5)
                priorities[i] += extra * np.cos(ratio * np.pi / 2)
        else:
            priorities[i] = np.inf
    max_priority = np.max(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 10
        elif priorities[i] == 0:
            priorities[i] = max_priority * 0.1
    return priorities
